import{_ as r,o as t,c as n,j as e,a as s,a1 as o}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"炎蔷薇徽章","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/7.物品与装备/4.奇物/3.B级/炎蔷薇徽章.md","filePath":"4.资源分区/7.物品与装备/4.奇物/3.B级/炎蔷薇徽章.md"}'),d={name:"4.资源分区/7.物品与装备/4.奇物/3.B级/炎蔷薇徽章.md"};function p(_,a,l,i,b,c){return t(),n("div",null,[...a[0]||(a[0]=[e("h1",{id:"炎蔷薇徽章",tabindex:"-1"},[s("炎蔷薇徽章 "),e("a",{class:"header-anchor",href:"#炎蔷薇徽章","aria-label":'Permalink to "炎蔷薇徽章"'},"​")],-1),e("table",{class:"bannerparthead"},[e("tbody",null,[e("tr",{id:"hdr"},[e("td",{class:"runninghead",nowrap:""},"TMD：新世短歌034")])])],-1),o('<h1 id="炎蔷薇徽章-1" tabindex="-1">炎蔷薇徽章 <a class="header-anchor" href="#炎蔷薇徽章-1" aria-label="Permalink to &quot;炎蔷薇徽章&quot;">​</a></h1><p>炎蔷薇徽章<br> 占用护符位</p><p>魔幻本质<br> 价格：B+2000<br> 介绍：<br> 这是一枚绘着某种奇异花朵的徽章，他们只在那高山之上的盛夏绽放，将花骨化作烈火，焚尽周遭的一切，<br> 世世代代，捍卫着他们族群的生存空间，留下新生代的种子。</p><p>“你愿意成为吾主的炎蔷薇吗？哪怕在烈火中化作残躯，无人认识？”<br> “若无摒弃一切的觉悟，就不要戴上此章”<br> 徽章的背面写着这么句话，同样的，徽章正面也留有话语。<br> “倘若你已心无疑虑，就还请专注那当下”<br> “惩戒敢胆来犯的敌人，坚定所要守护的事物，义无反顾的踏入火海”</p><p>效果：<br> 【契约职责】：这枚徽章很新，就像是刚刚收到一样，或许是你把它保养的很好的缘故。如果当前影片存在【骑士团】组织，则你会成为其中一员，且会承当守护边疆要地/朝圣要道/圣地等类似地点的职责，并获得相应的土地和资产；否则获得类似【骑士】/【贵族】的身份，并承当【边地侯爵】相似，承当守护边疆要地的职责。如果均没有，则由ST自行安排类似的身份。这是一个B级命运来源的背景身份能力。</p><p>【焚身烈火】：战斗场景内，以自由动作令你的身上燃起烈火，对你施加1点不可豁免的燃烧点数。只要这部分燃烧点数存在，那么你的白刃/肉搏攻击命中后会对目标额外施加2点不可豁免的燃烧点数。并且由于你身上常年反复被烈火焚烧，鲜有伤口能在你的身上停留，再为你提供免疫B级创伤来源效果的能力，且你的伤势不会自然恶化。</p><hr><p>Copyright ? 2025 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',8)])])}const m=r(d,[["render",p]]);export{f as __pageData,m as default};
